93	union njs_value_s {
94	    struct {
95	        uint32_t                      magic32;
96	        njs_value_type_t              type:8;  /* 5 bits */
97	
98	        /*
99	         * The truth field is set during value assignment and then can be
100	         * quickly tested by logical and conditional operations regardless
101	         * of value type.
102	         */
103	        uint8_t                       truth;
104	
105	        uint16_t                      magic16;
106	
107	        union {
108	            double                    number;
109	            njs_object_t              *object;
110	            njs_array_t               *array;
111	            njs_array_buffer_t        *array_buffer;
112	            njs_typed_array_t         *typed_array;
113	            njs_data_view_t           *data_view;
114	            njs_object_value_t        *object_value;
115	            njs_function_t            *function;
116	            njs_function_lambda_t     *lambda;
117	            njs_regexp_t              *regexp;
118	            njs_date_t                *date;
119	            njs_promise_t             *promise;
120	            njs_prop_handler_t        prop_handler;
121	            njs_value_t               *value;
122	            void                      *data;
123	        } u;
124	    } data;
125	
126	    struct {
127	        uint32_t                      atom_id;
128	        njs_value_type_t              type:8;  /* 5 bits */
129	        uint8_t                       truth;
130	        uint8_t                       token_type;
131	        uint8_t                       token_id;
132	        njs_string_t                  *data;
133	    } string;
134	
135	    struct {
136	        uint32_t                      atom_id;
137	        njs_value_type_t              type:8;  /* 5 bits */
138	        uint8_t                       truth;
139	    };
140	};
