524	#define njs_string_get(vm, value, str)                                        \
525	    do {                                                                      \
526	        njs_value_t  _dst;                                                    \
527	                                                                              \
528	        njs_assert(njs_is_string(value));                                     \
529	                                                                              \
530	        if (njs_slow_path((value)->string.data == NULL)) {                    \
531	            njs_assert((value)->atom_id != 0 /* NJS_ATOM_STRING_unknown */);  \
532	            njs_atom_to_value(vm, &_dst, (value)->atom_id);                   \
533	            njs_assert(njs_is_string(&_dst));                                 \
534	            njs_string_get_unsafe(&_dst, str);                                \
535	                                                                              \
536	        } else {                                                              \
537	            njs_string_get_unsafe(value, str);                                \
538	        }                                                                     \
539	    } while (0)
