34	njs_int_t
35	njs_value_to_primitive(njs_vm_t *vm, njs_value_t *dst, njs_value_t *value,
36	    njs_uint_t hint)
37	{
38	    njs_int_t            ret;
39	    njs_uint_t           tries, force_ordinary;
40	    njs_value_t          method, retval, arguments[2];
41	    njs_flathsh_query_t  fhq;
42	
43	    static const uint32_t atoms[] = {
44	        NJS_ATOM_STRING_valueOf,
45	        NJS_ATOM_STRING_toString,
46	    };
47	
48	    static const njs_uint_t atom_by_hint[] = {
49	        NJS_ATOM_STRING_number,
50	        NJS_ATOM_STRING_string,
51	        NJS_ATOM_STRING_default,
52	    };
53	
54	    if (njs_is_primitive(value)) {
55	        *dst = *value;
56	        return NJS_OK;
57	    }
58	
59	    tries = 0;
60	    fhq.proto = &njs_object_hash_proto;
61	
62	    if (!njs_is_object(value)) {
63	        goto error;
64	    }
65	
66	    force_ordinary = hint & NJS_HINT_FORCE_ORDINARY;
67	    hint &= ~NJS_HINT_FORCE_ORDINARY;
68	
69	    if (force_ordinary) {
70	        goto ordinary;
71	    }
72	
73	    fhq.key_hash = NJS_ATOM_SYMBOL_toPrimitive;
74	
75	    ret = njs_object_property(vm, njs_object(value), &fhq, &method);
76	    if (njs_slow_path(ret == NJS_ERROR)) {
77	        return ret;
78	    }
79	
80	    if (njs_is_function(&method)) {
81	        arguments[0] = *value;
82	
83	        njs_atom_to_value(vm, &arguments[1], atom_by_hint[hint]);
84	
85	        ret = njs_function_apply(vm, njs_function(&method), arguments, 2,
86	                                 &retval);
87	        if (njs_slow_path(ret != NJS_OK)) {
88	            return ret;
89	        }
90	
91	        if (njs_is_primitive(&retval)) {
92	            goto done;
93	        }
94	
95	        goto error;
96	    }
97	
98	ordinary:
99	
100	    if (hint != NJS_HINT_STRING) {
101	        hint = NJS_HINT_NUMBER;
102	    }
103	
104	    for ( ;; ) {
105	        ret = NJS_ERROR;
106	
107	        if (tries < 2) {
108	            hint ^= tries++;
109	
110	            fhq.key_hash = atoms[hint];
111	
112	            ret = njs_object_property(vm, njs_object(value), &fhq, &method);
113	            if (njs_slow_path(ret == NJS_ERROR)) {
114	                return ret;
115	            }
116	
117	            if (njs_is_function(&method)) {
118	                ret = njs_function_apply(vm, njs_function(&method), value, 1,
119	                                         &retval);
120	                if (njs_slow_path(ret != NJS_OK)) {
121	                    return ret;
122	                }
123	
124	                if (njs_is_primitive(&retval)) {
125	                    goto done;
126	                }
127	            }
128	
129	            /* Try the second method. */
130	            continue;
131	        }
132	
133	error:
134	
135	        njs_type_error(vm, "Cannot convert object to primitive value");
136	
137	        return NJS_ERROR;
138	    }
139	
140	done:
141	
142	    *dst = retval;
143	
144	    return NJS_OK;
145	}
