148	njs_array_t *
149	njs_value_enumerate(njs_vm_t *vm, njs_value_t *value, uint32_t flags)
150	{
151	    njs_int_t           ret;
152	    njs_value_t         keys;
153	    njs_object_value_t  obj_val;
154	    njs_exotic_slots_t  *slots;
155	
156	    if (njs_is_object(value)) {
157	        if ((flags & NJS_ENUM_KEYS) && (flags & NJS_ENUM_STRING)) {
158	            slots = njs_object_slots(value);
159	            if (slots != NULL && slots->keys != NULL) {
160	                ret = slots->keys(vm, value, &keys);
161	                if (njs_slow_path(ret != NJS_OK)) {
162	                    return NULL;
163	                }
164	
165	                return njs_array(&keys);
166	            }
167	        }
168	
169	        return njs_object_enumerate(vm, njs_object(value), flags);
170	    }
171	
172	    if (value->type != NJS_STRING) {
173	        return njs_array_alloc(vm, 1, 0, NJS_ARRAY_SPARE);
174	    }
175	
176	    obj_val.object = vm->string_object;
177	    obj_val.value = *value;
178	
179	    return njs_object_enumerate(vm, (njs_object_t *) &obj_val, flags);
180	}
