183	njs_array_t *
184	njs_value_own_enumerate(njs_vm_t *vm, njs_value_t *value, uint32_t flags)
185	{
186	    njs_int_t           ret, len;
187	    njs_array_t         *values, *entry;
188	    njs_value_t         keys, *k, *dst, *end;
189	    njs_object_value_t  obj_val;
190	    njs_exotic_slots_t  *slots;
191	
192	    if (njs_is_object(value)) {
193	        slots = njs_object_slots(value);
194	        if (slots == NULL || slots->keys == NULL) {
195	            return njs_object_own_enumerate(vm, njs_object(value), flags);
196	        }
197	
198	        ret = slots->keys(vm, value, &keys);
199	        if (njs_slow_path(ret != NJS_OK)) {
200	            return NULL;
201	        }
202	
203	        switch (njs_object_enum_kind(flags)) {
204	        case NJS_ENUM_KEYS:
205	            return njs_array(&keys);
206	
207	        case NJS_ENUM_VALUES:
208	            len = njs_array_len(&keys);
209	            k = njs_array(&keys)->start;
210	            end = k + len;
211	
212	            values = njs_array_alloc(vm, 1, len, 0);
213	            if (njs_slow_path(values == NULL)) {
214	                return NULL;
215	            }
216	
217	            dst = values->start;
218	
219	            while (k < end) {
220	                ret = njs_value_property_val(vm, value, k++, dst++);
221	                if (njs_slow_path(ret != NJS_OK)) {
222	                    return NULL;
223	                }
224	            }
225	
226	            return values;
227	
228	        case NJS_ENUM_BOTH:
229	        default:
230	            len = njs_array_len(&keys);
231	            k = njs_array(&keys)->start;
232	            end = k + len;
233	
234	            values = njs_array_alloc(vm, 1, len, 0);
235	            if (njs_slow_path(values == NULL)) {
236	                return NULL;
237	            }
238	
239	            dst = values->start;
240	
241	            while (k < end) {
242	                entry = njs_array_alloc(vm, 1, 2, 0);
243	                if (njs_slow_path(entry == NULL)) {
244	                    return NULL;
245	                }
246	
247	                ret = njs_value_property_val(vm, value, k, &entry->start[1]);
248	                if (njs_slow_path(ret != NJS_OK)) {
249	                    return NULL;
250	                }
251	
252	                njs_value_assign(&entry->start[0], k++);
253	
254	                njs_set_array(dst++, entry);
255	            }
256	
257	            return values;
258	        }
259	    }
260	
261	    if (value->type != NJS_STRING) {
262	        return njs_array_alloc(vm, 1, 0, NJS_ARRAY_SPARE);
263	    }
264	
265	    obj_val.object = vm->string_object;
266	    obj_val.value = *value;
267	
268	    return njs_object_own_enumerate(vm, (njs_object_t *) &obj_val, flags);
269	}
