593	/*
594	 * ES5.1, 8.12.1: [[GetOwnProperty]], [[GetProperty]].
595	 * The njs_property_query() returns values
596	 *   NJS_OK               property has been found in object,
597	 *     retval of type njs_object_prop_t * is in pq->fhq.value.
598	 *     in NJS_PROPERTY_QUERY_GET
599	 *       prop->type is NJS_PROPERTY or NJS_PROPERTY_HANDLER.
600	 *     in NJS_PROPERTY_QUERY_SET, NJS_PROPERTY_QUERY_DELETE
601	 *       prop->type is NJS_PROPERTY, NJS_PROPERTY_REF, NJS_PROPERTY_PLACE_REF,
602	 *       NJS_PROPERTY_TYPED_ARRAY_REF or
603	 *       NJS_PROPERTY_HANDLER.
604	 *   NJS_DECLINED         property was not found in object,
605	 *     if pq->fhq.value != NULL it contains retval of type
606	 *     njs_object_prop_t * where prop->type is NJS_WHITEOUT
607	 *   NJS_ERROR            exception has been thrown.
608	 */
609	
610	njs_int_t
611	njs_property_query(njs_vm_t *vm, njs_property_query_t *pq, njs_value_t *value,
612	    uint32_t atom_id)
613	{
614	    uint32_t        index;
615	    njs_int_t       ret;
616	    njs_object_t    *obj;
617	
618	    njs_assert(atom_id != NJS_ATOM_STRING_unknown);
619	
620	    switch (value->type) {
621	    case NJS_BOOLEAN:
622	    case NJS_NUMBER:
623	    case NJS_SYMBOL:
624	        index = njs_primitive_prototype_index(value->type);
625	        obj = njs_vm_proto(vm, index);
626	        break;
627	
628	    case NJS_STRING:
629	        if (njs_atom_is_number(atom_id)) {
630	            return njs_string_property_query(vm, pq, value,
631	                                             njs_atom_number(atom_id));
632	        }
633	
634	        obj = &vm->string_object;
635	        break;
636	
637	    case NJS_OBJECT:
638	    case NJS_ARRAY:
639	    case NJS_FUNCTION:
640	    case NJS_ARRAY_BUFFER:
641	    case NJS_DATA_VIEW:
642	    case NJS_TYPED_ARRAY:
643	    case NJS_REGEXP:
644	    case NJS_DATE:
645	    case NJS_PROMISE:
646	    case NJS_OBJECT_VALUE:
647	        obj = njs_object(value);
648	        break;
649	
650	    case NJS_UNDEFINED:
651	    case NJS_NULL:
652	    default:
653	        njs_atom_string_get(vm, atom_id, &pq->fhq.key);
654	        njs_type_error(vm, "cannot get property \"%V\" of %s", &pq->fhq.key,
655	                       njs_type_string(value->type));
656	        return NJS_ERROR;
657	    }
658	
659	    ret = njs_object_property_query(vm, pq, obj, atom_id);
660	
661	    if (njs_slow_path(ret == NJS_DECLINED && obj->slots != NULL)) {
662	        return njs_external_property_query(vm, pq, value);
663	    }
664	
665	    return ret;
666	}
667	
668	
669	njs_inline njs_int_t
670	njs_object_property_query(njs_vm_t *vm, njs_property_query_t *pq,
671	    njs_object_t *object, uint32_t atom_id)
672	{
673	    double              num;
674	    njs_int_t           ret;
675	    njs_bool_t          own;
676	    njs_value_t         key;
677	    njs_array_t         *array;
678	    njs_object_t        *proto;
679	    njs_object_prop_t   *prop;
680	    njs_typed_array_t   *tarray;
681	    njs_object_value_t  *ov;
682	
683	    pq->fhq.proto = &njs_object_hash_proto;
684	
685	    own = pq->own;
686	    pq->own = 1;
687	
688	    proto = object;
689	
690	    do {
691	        switch (proto->type) {
692	        case NJS_ARRAY:
693	            array = (njs_array_t *) proto;
694	
695	            if (njs_fast_path(njs_atom_is_number(atom_id))) {
696	                ret = njs_array_property_query(vm, pq, array,
697	                                               njs_atom_number(atom_id), atom_id);
698	                if (njs_fast_path(ret != NJS_DECLINED)) {
699	                    return (ret == NJS_DONE) ? NJS_DECLINED : ret;
700	                }
701	            }
702	
703	            ret = njs_atom_to_value(vm, &key, atom_id);
704	            if (njs_slow_path(ret != NJS_OK)) {
705	                return ret;
706	            }
707	
708	            num = njs_key_to_index(&key);
709	
710	            if (njs_key_is_integer_index(num, &key)) {
711	                ret = njs_array_property_query(vm, pq, array, num, atom_id);
712	                if (njs_fast_path(ret != NJS_DECLINED)) {
713	                    return (ret == NJS_DONE) ? NJS_DECLINED : ret;
714	                }
715	            }
716	
717	            break;
718	
719	        case NJS_TYPED_ARRAY:
720	            if (njs_fast_path(njs_atom_is_number(atom_id))) {
721	                tarray = (njs_typed_array_t *) proto;
722	                return njs_typed_array_property_query(vm, pq, tarray,
723	                                                      njs_atom_number(atom_id));
724	            }
725	
726	            ret = njs_atom_to_value(vm, &key, atom_id);
727	            if (njs_slow_path(ret != NJS_OK)) {
728	                return ret;
729	            }
730	
731	            num = njs_key_to_index(&key);
732	
733	            if (!isnan(num)) {
734	                return NJS_DECLINED;
735	            }
736	
737	            break;
738	
739	        case NJS_OBJECT_VALUE:
740	            ov = (njs_object_value_t *) proto;
741	            if (!njs_is_string(&ov->value) || proto->error_data) {
742	                break;
743	            }
744	
745	            if (njs_fast_path(njs_atom_is_number(atom_id))) {
746	                ov = (njs_object_value_t *) proto;
747	                ret = njs_string_property_query(vm, pq, &ov->value,
748	                                                njs_atom_number(atom_id));
749	                if (njs_fast_path(ret != NJS_DECLINED)) {
750	                    return ret;
751	                }
752	            }
753	
754	            break;
755	
756	        default:
757	            break;
758	        }
759	
760	        pq->fhq.key_hash = atom_id;
761	
762	        ret = njs_flathsh_unique_find(&proto->hash, &pq->fhq);
763	
764	        if (ret == NJS_OK) {
765	            prop = pq->fhq.value;
766	
767	            if (prop->type != NJS_WHITEOUT) {
768	                return ret;
769	            }
770	
771	            if (pq->own) {
772	                pq->own_whiteout = &proto->hash;
773	            }
774	
775	        } else {
776	            ret = njs_flathsh_unique_find(&proto->shared_hash, &pq->fhq);
777	            if (ret == NJS_OK) {
778	                return njs_prop_private_copy(vm, pq, proto);
779	            }
780	        }
781	
782	        if (own) {
783	            return NJS_DECLINED;
784	        }
785	
786	        pq->own = 0;
787	        proto = proto->__proto__;
788	
789	    } while (proto != NULL);
790	
791	    return NJS_DECLINED;
792	}
793	
794	
795	static njs_int_t
796	njs_array_property_query(njs_vm_t *vm, njs_property_query_t *pq,
797	    njs_array_t *array, uint32_t index, uint32_t atom_id)
798	{
799	    int64_t            length;
800	    uint64_t           size;
801	    njs_int_t          ret;
802	    njs_bool_t         resized;
803	    njs_value_t        *setval, value;
804	    njs_object_prop_t  *prop;
805	
806	    resized = 0;
807	
808	    if (pq->query == NJS_PROPERTY_QUERY_SET) {
809	        if (!array->object.extensible) {
810	            return NJS_DECLINED;
811	        }
812	
813	        if (njs_fast_path(array->object.fast_array)) {
814	            if (njs_fast_path(index < NJS_ARRAY_LARGE_OBJECT_LENGTH)) {
815	                if (index >= array->length) {
816	                    size = index - array->length + 1;
817	
818	                    ret = njs_array_expand(vm, array, 0, size);
819	                    if (njs_slow_path(ret != NJS_OK)) {
820	                        return ret;
821	                    }
822	
823	                    setval = &array->start[array->length];
824	
825	                    while (size != 0) {
826	                        njs_set_invalid(setval);
827	                        setval++;
828	                        size--;
829	                    }
830	
831	                    array->length = index + 1;
832	                    resized = 1;
833	                }
834	
835	                goto prop;
836	            }
837	
838	            ret = njs_array_convert_to_slow_array(vm, array);
839	            if (njs_slow_path(ret != NJS_OK)) {
840	                return ret;
841	            }
842	        }
843	
844	        njs_set_array(&value, array);
845	
846	        ret = njs_object_length(vm, &value, &length);
847	        if (njs_slow_path(ret != NJS_OK)) {
848	            return ret;
849	        }
850	
851	        if ((index + 1) > length) {
852	            ret = njs_array_length_redefine(vm, &value, index + 1, 1);
853	            if (njs_slow_path(ret != NJS_OK)) {
854	                return ret;
855	            }
856	        }
857	
858	        pq->fhq.key_hash = atom_id;
859	
860	        ret = njs_flathsh_unique_find(&array->object.hash, &pq->fhq);
861	        if (ret == NJS_OK) {
862	            prop = pq->fhq.value;
863	
864	            if (prop->type != NJS_WHITEOUT) {
865	                return NJS_OK;
866	            }
867	
868	            if (pq->own) {
869	                pq->own_whiteout = &array->object.hash;
870	            }
871	
872	            return NJS_DECLINED;
873	        }
874	
875	        return NJS_DONE;
876	    }
877	
878	    if (njs_slow_path(!array->object.fast_array)) {
879	        return NJS_DECLINED;
880	    }
881	
882	    if (index >= array->length) {
883	        return NJS_DECLINED;
884	    }
885	
886	prop:
887	
888	    prop = &pq->scratch;
889	
890	    if (pq->query == NJS_PROPERTY_QUERY_GET) {
891	        if (!njs_is_valid(&array->start[index])) {
892	            return NJS_DECLINED;
893	        }
894	
895	        njs_value_assign(njs_prop_value(prop), &array->start[index]);
896	        prop->type = NJS_PROPERTY;
897	
898	    } else {
899	        njs_prop_ref(prop) = &array->start[index];
900	        prop->type = resized ? NJS_PROPERTY_PLACE_REF : NJS_PROPERTY_REF;
901	    }
902	
903	    prop->writable = 1;
904	    prop->enumerable = 1;
905	    prop->configurable = 1;
906	
907	    pq->fhq.value = prop;
908	
909	    return NJS_OK;
910	}
911	
912	
913	static njs_int_t
914	njs_typed_array_property_query(njs_vm_t *vm, njs_property_query_t *pq,
915	    njs_typed_array_t *array, uint32_t index)
916	{
917	    njs_object_prop_t  *prop;
918	
919	    if (njs_slow_path(njs_is_detached_buffer(array->buffer))) {
920	        njs_type_error(vm, "detached buffer");
921	        return NJS_ERROR;
922	    }
923	
924	    if (index >= njs_typed_array_length(array)) {
925	        return NJS_DECLINED;
926	    }
927	
928	    prop = &pq->scratch;
929	
930	    if (pq->query == NJS_PROPERTY_QUERY_GET) {
931	        njs_set_number(njs_prop_value(prop),
932	                       njs_typed_array_prop(array, index));
933	        prop->type = NJS_PROPERTY;
934	
935	    } else {
936	        njs_prop_typed_ref(prop) = array;
937	        njs_prop_magic32(prop) = index;
938	        prop->type = NJS_PROPERTY_TYPED_ARRAY_REF;
939	    }
940	
941	    prop->writable = 1;
942	    prop->enumerable = 1;
943	    prop->configurable = 0;
944	
945	    pq->fhq.value = prop;
946	
947	    return NJS_OK;
948	}
949	
950	
951	static njs_int_t
952	njs_string_property_query(njs_vm_t *vm, njs_property_query_t *pq,
953	    njs_value_t *object, uint32_t index)
954	{
955	    njs_slice_prop_t   slice;
956	    njs_object_prop_t  *prop;
957	    njs_string_prop_t  string;
958	
959	    prop = &pq->scratch;
960	
961	    slice.start = index;
962	    slice.length = 1;
963	    slice.string_length = njs_string_prop(vm, &string, object);
964	
965	    if (slice.start < slice.string_length) {
966	        /*
967	         * A single codepoint string fits in retval
968	         * so the function cannot fail.
969	         */
970	        (void) njs_string_slice(vm, njs_prop_value(prop), &string, &slice);
971	
972	        prop->type = NJS_PROPERTY;
973	        prop->writable = 0;
974	        prop->enumerable = 1;
975	        prop->configurable = 0;
976	
977	        pq->fhq.value = prop;
978	
979	        return NJS_OK;
980	    }
981	
982	    return NJS_DECLINED;
983	}
