985	
986	static njs_int_t
987	njs_external_property_query(njs_vm_t *vm, njs_property_query_t *pq,
988	    njs_value_t *value)
989	{
990	    njs_object_prop_t   *prop;
991	    njs_exotic_slots_t  *slots;
992	
993	    slots = njs_object_slots(value);
994	
995	    if (njs_slow_path(slots->prop_handler == NULL)) {
996	        return NJS_DECLINED;
997	    }
998	
999	    pq->temp = 1;
1000	    prop = &pq->scratch;
1001	
1002	    njs_memzero(prop, sizeof(njs_object_prop_t));
1003	
1004	    /*
1005	     * njs_memzero() does also:
1006	     *   prop->type = NJS_PROPERTY;
1007	     *   prop->writable = 0;
1008	     *   prop->configurable = 0;
1009	     */
1010	
1011	    njs_prop_magic32(prop) = slots->magic32;
1012	
1013	    pq->fhq.value = prop;
1014	
1015	    prop->type = NJS_PROPERTY;
1016	    prop->writable = slots->writable;
1017	    prop->configurable = slots->configurable;
1018	    prop->enumerable = slots->enumerable;
1019	
1020	    switch (pq->query) {
1021	
1022	    case NJS_PROPERTY_QUERY_GET:
1023	        return slots->prop_handler(vm, prop, pq->fhq.key_hash, value, NULL,
1024	                                   njs_prop_value(prop));
1025	
1026	    case NJS_PROPERTY_QUERY_SET:
1027	        if (slots->writable == 0) {
1028	            return NJS_OK;
1029	        }
1030	
1031	        break;
1032	
1033	    case NJS_PROPERTY_QUERY_DELETE:
1034	        if (slots->configurable == 0) {
1035	            return NJS_OK;
1036	        }
1037	
1038	        break;
1039	    }
1040	
1041	    prop->type = NJS_PROPERTY_HANDLER;
1042	    njs_prop_handler(prop) = slots->prop_handler;
1043	
1044	    return NJS_OK;
1045	}
