1047	
1048	njs_int_t
1049	njs_value_property(njs_vm_t *vm, njs_value_t *value, uint32_t atom_id,
1050	    njs_value_t *retval)
1051	{
1052	    uint32_t              index;
1053	    njs_int_t             ret;
1054	    njs_array_t          *array;
1055	    njs_object_prop_t     *prop;
1056	    njs_typed_array_t     *tarray;
1057	    njs_property_query_t  pq;
1058	
1059	    if (njs_fast_path(njs_atom_is_number(atom_id))) {
1060	        index = njs_atom_number(atom_id);
1061	
1062	        if (njs_is_typed_array(value)) {
1063	            tarray = njs_typed_array(value);
1064	
1065	            if (njs_slow_path(njs_is_detached_buffer(tarray->buffer))) {
1066	                goto not_found;
1067	            }
1068	
1069	            if (njs_slow_path(index >= njs_typed_array_length(tarray))) {
1070	                goto slow_path;
1071	            }
1072	
1073	            njs_set_number(retval, njs_typed_array_prop(tarray, index));
1074	
1075	            return NJS_OK;
1076	        }
1077	
1078	        if (njs_slow_path(!(njs_is_object(value)
1079	                            && njs_object(value)->fast_array)))
1080	        {
1081	            goto slow_path;
1082	        }
1083	
1084	        /* njs_is_fast_array() */
1085	
1086	        array = njs_array(value);
1087	
1088	        if (njs_slow_path(index >= array->length
1089	                          || !njs_is_valid(&array->start[index])))
1090	        {
1091	            goto slow_path;
1092	        }
1093	
1094	        njs_value_assign(retval, &array->start[index]);
1095	
1096	        return NJS_OK;
1097	    }
1098	
1099	slow_path:
1100	
1101	    njs_property_query_init(&pq, NJS_PROPERTY_QUERY_GET, 0);
1102	
1103	    ret = njs_property_query(vm, &pq, value, atom_id);
1104	
1105	    switch (ret) {
1106	
1107	    case NJS_OK:
1108	        prop = pq.fhq.value;
1109	
1110	        switch (prop->type) {
1111	        case NJS_PROPERTY:
1112	        case NJS_ACCESSOR:
1113	            if (njs_is_data_descriptor(prop)) {
1114	                njs_value_assign(retval, njs_prop_value(prop));
1115	                break;
1116	            }
1117	
1118	            if (njs_prop_getter(prop) == NULL) {
1119	                njs_set_undefined(retval);
1120	                break;
1121	            }
1122	
1123	            return njs_function_apply(vm, njs_prop_getter(prop), value, 1,
1124	                                      retval);
1125	
1126	        case NJS_PROPERTY_HANDLER:
1127	            pq.scratch = *prop;
1128	            prop = &pq.scratch;
1129	            ret = njs_prop_handler(prop)(vm, prop, atom_id, value, NULL,
1130	                                         njs_prop_value(prop));
1131	
1132	            if (njs_slow_path(ret != NJS_OK)) {
1133	                if (ret == NJS_ERROR) {
1134	                    return ret;
1135	                }
1136	
1137	                njs_set_undefined(njs_prop_value(prop));
1138	            }
1139	
1140	            njs_value_assign(retval, njs_prop_value(prop));
1141	
1142	            break;
1143	
1144	        default:
1145	            njs_internal_error(vm, "unexpected property type \"%s\" "
1146	                               "while getting",
1147	                               njs_prop_type_string(prop->type));
1148	
1149	            return NJS_ERROR;
1150	        }
1151	
1152	        break;
1153	
1154	    case NJS_DECLINED:
1155	not_found:
1156	        njs_set_undefined(retval);
1157	
1158	        return NJS_DECLINED;
1159	
1160	    case NJS_ERROR:
1161	    default:
1162	
1163	        return NJS_ERROR;
1164	    }
1165	
1166	    return NJS_OK;
1167	}
