1170	njs_int_t
1171	njs_value_property_set(njs_vm_t *vm, njs_value_t *value, uint32_t atom_id,
1172	    njs_value_t *setval)
1173	{
1174	    uint32_t              index;
1175	    njs_int_t             ret;
1176	    njs_array_t           *array;
1177	    njs_value_t           retval, key;
1178	    njs_object_prop_t     *prop;
1179	    njs_typed_array_t     *tarray;
1180	    njs_flathsh_elt_t     *elt;
1181	    njs_flathsh_descr_t   *h;
1182	    njs_property_query_t  pq;
1183	
1184	    if (njs_fast_path(njs_atom_is_number(atom_id))) {
1185	        index = njs_atom_number(atom_id);
1186	
1187	        if (njs_is_typed_array(value)) {
1188	            tarray = njs_typed_array(value);
1189	
1190	            if (njs_fast_path(index < njs_typed_array_length(tarray))) {
1191	                return njs_typed_array_set_value(vm, tarray, index, setval);
1192	            }
1193	
1194	            return NJS_OK;
1195	        }
1196	
1197	        if (njs_slow_path(!(njs_is_object(value)
1198	                            && njs_object(value)->fast_array)))
1199	        {
1200	            goto slow_path;
1201	        }
1202	
1203	        /* NJS_ARRAY */
1204	
1205	        array = njs_array(value);
1206	
1207	        if (njs_slow_path(index >= array->length)) {
1208	            goto slow_path;
1209	        }
1210	
1211	        njs_value_assign(&array->start[index], setval);
1212	
1213	        return NJS_OK;
1214	    }
1215	
1216	slow_path:
1217	
1218	    if (njs_is_primitive(value)) {
1219	        njs_type_error(vm, "property set on primitive %s type",
1220	                       njs_type_string(value->type));
1221	        return NJS_ERROR;
1222	    }
1223	
1224	    njs_property_query_init(&pq, NJS_PROPERTY_QUERY_SET, 0);
1225	
1226	    ret = njs_property_query(vm, &pq, value, atom_id);
1227	
1228	    switch (ret) {
1229	
1230	    case NJS_OK:
1231	        prop = pq.fhq.value;
1232	
1233	        if (njs_is_data_descriptor(prop)) {
1234	            if (!prop->writable) {
1235	                njs_atom_string_get(vm, atom_id, &pq.fhq.key);
1236	                njs_type_error(vm,
1237	                             "Cannot assign to read-only property \"%V\" of %s",
1238	                               &pq.fhq.key, njs_type_string(value->type));
1239	                return NJS_ERROR;
1240	            }
1241	
1242	        } else {
1243	            if (njs_prop_setter(prop) != NULL) {
1244	                return njs_function_call(vm, njs_prop_setter(prop),
1245	                                         value, setval, 1, &retval);
1246	            }
1247	
1248	            njs_atom_string_get(vm, atom_id, &pq.fhq.key);
1249	            njs_type_error(vm,
1250	                     "Cannot set property \"%V\" of %s which has only a getter",
1251	                           &pq.fhq.key, njs_type_string(value->type));
1252	            return NJS_ERROR;
1253	        }
1254	
1255	        if (prop->type == NJS_PROPERTY_HANDLER) {
1256	            ret = njs_prop_handler(prop)(vm, prop, atom_id, value,
1257	                                         setval, &retval);
1258	            if (njs_slow_path(ret != NJS_DECLINED)) {
1259	                return ret;
1260	            }
1261	        }
1262	
1263	        if (pq.own) {
1264	            switch (prop->type) {
1265	            case NJS_PROPERTY:
1266	                if (njs_is_array(value)) {
1267	                    if (njs_slow_path(atom_id == NJS_ATOM_STRING_length)) {
1268	                        return njs_array_length_set(vm, value, prop, setval);
1269	                    }
1270	                }
1271	
1272	                goto found;
1273	
1274	            case NJS_PROPERTY_REF:
1275	            case NJS_PROPERTY_PLACE_REF:
1276	                njs_value_assign(njs_prop_ref(prop), setval);
1277	                return NJS_OK;
1278	
1279	            case NJS_PROPERTY_TYPED_ARRAY_REF:
1280	                return njs_typed_array_set_value(vm,
1281	                                         njs_typed_array(njs_prop_value(prop)),
1282	                                         njs_prop_magic32(prop),
1283	                                         setval);
1284	
1285	            default:
1286	                njs_internal_error(vm, "unexpected property type \"%s\" "
1287	                                   "while setting",
1288	                                   njs_prop_type_string(prop->type));
1289	
1290	                return NJS_ERROR;
1291	            }
1292	
1293	            break;
1294	        }
1295	
1296	        /* Fall through. */
1297	
1298	    case NJS_DECLINED:
1299	        if (njs_slow_path(pq.own_whiteout != NULL)) {
1300	
1301	            /*
1302	             * Previously deleted property.
1303	             *
1304	             * delete it, and then
1305	             * insert it again as new one to preserve insertion order.
1306	             */
1307	
1308	            if (!njs_object(value)->extensible) {
1309	                goto fail;
1310	            }
1311	
1312	            pq.fhq.pool = vm->mem_pool;
1313	
1314	            int rc = njs_flathsh_unique_delete(pq.own_whiteout, &pq.fhq);
1315	            if (rc != NJS_OK) {
1316	                return NJS_ERROR;
1317	            }
1318	
1319	            h = pq.own_whiteout->slot;
1320	
1321	            if (h == NULL) {
1322	                h = njs_flathsh_new(&pq.fhq);
1323	                if (njs_slow_path(h == NULL)) {
1324	                    return NJS_ERROR;
1325	                }
1326	
1327	                pq.own_whiteout->slot = h;
1328	            }
1329	
1330	            elt = njs_flathsh_add_elt(pq.own_whiteout, &pq.fhq);
1331	            if (njs_slow_path(elt == NULL)) {
1332	                return NJS_ERROR;
1333	            }
1334	
1335	            prop = (njs_object_prop_t *) elt;
1336	            prop->type = NJS_PROPERTY;
1337	            prop->enumerable = 1;
1338	            prop->configurable = 1;
1339	            prop->writable = 1;
1340	
1341	            goto found;
1342	        }
1343	
1344	        if (njs_slow_path(pq.own && njs_is_typed_array(value)
1345	                          && !njs_atom_is_number(atom_id)))
1346	        {
1347	            /* Integer-Indexed Exotic Objects [[DefineOwnProperty]]. */
1348	
1349	            ret = njs_atom_to_value(vm, &key, atom_id);
1350	            if (njs_slow_path(ret != NJS_OK)) {
1351	                return ret;
1352	            }
1353	
1354	            if (!isnan(njs_string_to_index(&key))) {
1355	                return NJS_OK;
1356	            }
1357	        }
1358	
1359	        break;
1360	
1361	    case NJS_ERROR:
1362	    default:
1363	
1364	        return NJS_ERROR;
1365	    }
1366	
1367	    if (njs_slow_path(!njs_object(value)->extensible)) {
1368	        goto fail;
1369	    }
1370	
1371	
1372	    pq.fhq.replace = 0;
1373	    pq.fhq.key_hash = atom_id;
1374	    pq.fhq.pool = vm->mem_pool;
1375	
1376	    ret = njs_flathsh_unique_insert(njs_object_hash(value), &pq.fhq);
1377	    if (njs_slow_path(ret != NJS_OK)) {
1378	        njs_internal_error(vm, "flathsh insert failed");
1379	        return NJS_ERROR;
1380	    }
1381	
1382	    prop = pq.fhq.value;
1383	    prop->type = NJS_PROPERTY;
1384	    prop->enumerable = 1;
1385	    prop->configurable = 1;
1386	    prop->writable = 1;
1387	
1388	found:
1389	
1390	    njs_value_assign(njs_prop_value(prop), setval);
1391	
1392	    return NJS_OK;
1393	
1394	fail:
1395	
1396	    njs_atom_string_get(vm, atom_id, &pq.fhq.key);
1397	    njs_type_error(vm, "Cannot add property \"%V\", object is not extensible",
1398	                   &pq.fhq.key);
1399	
1400	    return NJS_ERROR;
1401	}
1402	
1403	
1404	njs_int_t
1405	njs_value_property_delete(njs_vm_t *vm, njs_value_t *value, uint32_t atom_id,
1406	    njs_value_t *removed, njs_bool_t thrw)
1407	{
1408	    uint32_t              index;
1409	    njs_int_t             ret;
1410	    njs_array_t           *array;
1411	    njs_object_prop_t     *prop;
1412	    njs_property_query_t  pq;
1413	
1414	    if (njs_fast_path(njs_atom_is_number(atom_id))) {
1415	        if (njs_slow_path(!(njs_is_fast_array(value)))) {
1416	            goto slow_path;
1417	        }
1418	
1419	        index = (uint32_t) njs_atom_number(atom_id);
1420	
1421	        array = njs_array(value);
1422	
1423	        if (njs_slow_path(index >= array->length)) {
1424	            goto slow_path;
1425	        }
1426	
1427	        njs_value_assign(&array->start[index], &njs_value_invalid);
1428	
1429	        return NJS_OK;
1430	    }
1431	
1432	slow_path:
1433	
1434	    njs_property_query_init(&pq, NJS_PROPERTY_QUERY_DELETE, 1);
1435	
1436	    ret = njs_property_query(vm, &pq, value, atom_id);
1437	    if (njs_slow_path(ret != NJS_OK)) {
1438	        return ret;
1439	    }
1440	
1441	    prop = pq.fhq.value;
1442	
1443	    if (njs_slow_path(!prop->configurable)) {
1444	        if (thrw) {
1445	            njs_atom_string_get(vm, atom_id, &pq.fhq.key);
1446	            njs_type_error(vm, "Cannot delete property \"%V\" of %s",
1447	                           &pq.fhq.key, njs_type_string(value->type));
1448	            return NJS_ERROR;
1449	        }
1450	
1451	        return NJS_OK;
1452	    }
1453	
1454	    switch (prop->type) {
1455	    case NJS_PROPERTY_HANDLER:
1456	        if (njs_is_object(value) && njs_object_slots(value) != NULL) {
1457	            ret = njs_prop_handler(prop)(vm, prop, atom_id, value, NULL,
1458	                                         NULL);
1459	            if (njs_slow_path(ret != NJS_DECLINED)) {
1460	                return ret;
1461	            }
1462	        }
1463	
1464	        /* Fall through. */
1465	
1466	    case NJS_PROPERTY:
1467	        break;
1468	
1469	    case NJS_ACCESSOR:
1470	        if (removed == NULL) {
1471	            break;
1472	        }
1473	
1474	        if (njs_prop_getter(prop) == NULL) {
1475	            njs_set_undefined(removed);
1476	            break;
1477	        }
1478	
1479	        return njs_function_apply(vm, njs_prop_getter(prop), value, 1, removed);
1480	
1481	    case NJS_PROPERTY_REF:
1482	    case NJS_PROPERTY_PLACE_REF:
1483	        if (removed != NULL) {
1484	            njs_value_assign(removed, njs_prop_ref(prop));
1485	        }
1486	
1487	        njs_set_invalid(njs_prop_ref(prop));
1488	        return NJS_OK;
1489	
1490	    default:
1491	        njs_internal_error(vm, "unexpected property type \"%s\" "
1492	                           "while deleting", njs_prop_type_string(prop->type));
1493	        return NJS_ERROR;
1494	    }
1495	
1496	    if (removed != NULL) {
1497	        if (njs_is_valid(njs_prop_value(prop))) {
1498	            njs_value_assign(removed, njs_prop_value(prop));
1499	
1500	        } else {
1501	            njs_set_undefined(removed);
1502	        }
1503	    }
1504	
1505	    prop->type = NJS_WHITEOUT;
1506	
1507	    return NJS_OK;
1508	}
