1511	njs_int_t
1512	njs_primitive_value_to_string(njs_vm_t *vm, njs_value_t *dst,
1513	    const njs_value_t *src)
1514	{
1515	    const njs_value_t  *value;
1516	
1517	    switch (src->type) {
1518	
1519	    case NJS_NULL:
1520	        njs_atom_to_value(vm, dst, NJS_ATOM_STRING_null);
1521	        return NJS_OK;
1522	
1523	    case NJS_UNDEFINED:
1524	        njs_atom_to_value(vm, dst, NJS_ATOM_STRING_undefined);
1525	        return NJS_OK;
1526	
1527	    case NJS_BOOLEAN:
1528	        if (njs_is_true(src)) {
1529	            njs_atom_to_value(vm, dst, NJS_ATOM_STRING_true);
1530	
1531	        } else {
1532	            njs_atom_to_value(vm, dst, NJS_ATOM_STRING_false);
1533	        }
1534	
1535	        return NJS_OK;
1536	
1537	    case NJS_NUMBER:
1538	        return njs_number_to_string(vm, dst, src);
1539	
1540	    case NJS_SYMBOL:
1541	        njs_symbol_conversion_failed(vm, 1);
1542	        return NJS_ERROR;
1543	
1544	    case NJS_STRING:
1545	        value = src;
1546	        break;
1547	
1548	    default:
1549	        return NJS_ERROR;
1550	    }
1551	
1552	    *dst = *value;
1553	
1554	    return NJS_OK;
1555	}
