1557	
1558	njs_int_t
1559	njs_primitive_value_to_chain(njs_vm_t *vm, njs_chb_t *chain,
1560	    const njs_value_t *src)
1561	{
1562	    njs_string_prop_t  string;
1563	
1564	    switch (src->type) {
1565	
1566	    case NJS_NULL:
1567	        njs_chb_append_literal(chain, "null");
1568	        return njs_length("null");
1569	
1570	    case NJS_UNDEFINED:
1571	        njs_chb_append_literal(chain, "undefined");
1572	        return njs_length("undefined");
1573	
1574	    case NJS_BOOLEAN:
1575	        if (njs_is_true(src)) {
1576	            njs_chb_append_literal(chain, "true");
1577	            return njs_length("true");
1578	
1579	        } else {
1580	            njs_chb_append_literal(chain, "false");
1581	            return njs_length("false");
1582	        }
1583	
1584	    case NJS_NUMBER:
1585	        return njs_number_to_chain(vm, chain, njs_number(src));
1586	
1587	    case NJS_SYMBOL:
1588	        njs_symbol_conversion_failed(vm, 1);
1589	        return NJS_ERROR;
1590	
1591	    case NJS_STRING:
1592	        (void) njs_string_prop(vm, &string, src);
1593	        njs_chb_append(chain, string.start, string.size);
1594	        return string.length;
1595	
1596	    default:
1597	        return NJS_ERROR;
1598	    }
1599	}
