1602	njs_int_t
1603	njs_value_to_integer(njs_vm_t *vm, njs_value_t *value, int64_t *dst)
1604	{
1605	    double     num;
1606	    njs_int_t  ret;
1607	
1608	    ret = njs_value_to_number(vm, value, &num);
1609	    if (njs_slow_path(ret != NJS_OK)) {
1610	        return ret;
1611	    }
1612	
1613	    *dst = njs_number_to_integer(num);
1614	
1615	    return NJS_OK;
1616	}
