1618	
1619	njs_int_t
1620	njs_value_to_object(njs_vm_t *vm, njs_value_t *value)
1621	{
1622	    njs_uint_t          index;
1623	    njs_object_value_t  *object;
1624	
1625	    if (njs_slow_path(njs_is_null_or_undefined(value))) {
1626	        njs_type_error(vm, "cannot convert null or undefined to object");
1627	        return NJS_ERROR;
1628	    }
1629	
1630	    if (njs_fast_path(njs_is_object(value))) {
1631	        return NJS_OK;
1632	    }
1633	
1634	    if (njs_is_primitive(value)) {
1635	        index = njs_primitive_prototype_index(value->type);
1636	        object = njs_object_value_alloc(vm, index, 0, value);
1637	        if (njs_slow_path(object == NULL)) {
1638	            return NJS_ERROR;
1639	        }
1640	
1641	        njs_set_object_value(value, object);
1642	
1643	        return NJS_OK;
1644	    }
1645	
1646	    njs_type_error(vm, "cannot convert %s to object",
1647	                   njs_type_string(value->type));
1648	
1649	    return NJS_ERROR;
1650	}
1651	
1652	
1653	void
1654	njs_symbol_conversion_failed(njs_vm_t *vm, njs_bool_t to_string)
1655	{
1656	    njs_type_error(vm, to_string
1657	        ? "Cannot convert a Symbol value to a string"
1658	        : "Cannot convert a Symbol value to a number");
1659	}
