1661	
1662	njs_int_t
1663	njs_value_construct(njs_vm_t *vm, njs_value_t *constructor, njs_value_t *args,
1664	    njs_uint_t nargs, njs_value_t *retval)
1665	{
1666	    njs_value_t   this;
1667	    njs_object_t  *object;
1668	
1669	    object = njs_function_new_object(vm, constructor);
1670	    if (njs_slow_path(object == NULL)) {
1671	        return NJS_ERROR;
1672	    }
1673	
1674	    njs_set_object(&this, object);
1675	
1676	    return njs_function_call2(vm, njs_function(constructor), &this, args,
1677	                              nargs, retval, 1);
1678	}
