1680	
1681	njs_int_t
1682	njs_value_species_constructor(njs_vm_t *vm, njs_value_t *object,
1683	    njs_value_t *default_constructor, njs_value_t *dst)
1684	{
1685	    njs_int_t    ret;
1686	    njs_value_t  constructor, retval;
1687	
1688	    ret = njs_value_property(vm, object, NJS_ATOM_STRING_constructor,
1689	                             &constructor);
1690	    if (njs_slow_path(ret == NJS_ERROR)) {
1691	        return NJS_ERROR;
1692	    }
1693	
1694	    if (njs_is_undefined(&constructor)) {
1695	        goto default_constructor;
1696	    }
1697	
1698	    if (njs_slow_path(!njs_is_object(&constructor))) {
1699	        njs_type_error(vm, "constructor is not object");
1700	        return NJS_ERROR;
1701	    }
1702	
1703	    ret = njs_value_property(vm, &constructor, NJS_ATOM_SYMBOL_species,
1704	                             &retval);
1705	    if (njs_slow_path(ret == NJS_ERROR)) {
1706	        return NJS_ERROR;
1707	    }
1708	
1709	    if (njs_value_is_null_or_undefined(&retval)) {
1710	        goto default_constructor;
1711	    }
1712	
1713	    if (!njs_is_function(&retval)) {
1714	        njs_type_error(vm, "object does not contain a constructor");
1715	        return NJS_ERROR;
1716	    }
1717	
1718	    *dst = retval;
1719	
1720	    return NJS_OK;
1721	
1722	default_constructor:
1723	
1724	    *dst = *default_constructor;
1725	
1726	    return NJS_OK;
1727	}
