1729	
1730	njs_int_t
1731	njs_value_method(njs_vm_t *vm, njs_value_t *value, uint32_t atom_id,
1732	    njs_value_t *retval)
1733	{
1734	    njs_int_t  ret;
1735	
1736	    ret = njs_value_to_object(vm, value);
1737	    if (njs_slow_path(ret != NJS_OK)) {
1738	        return ret;
1739	    }
1740	
1741	    ret = njs_value_property(vm, value, atom_id, retval);
1742	    if (njs_slow_path(ret != NJS_OK)) {
1743	        return (ret == NJS_DECLINED) ? NJS_OK : ret;
1744	    }
1745	
1746	    if (njs_slow_path(!njs_is_function(retval))) {
1747	        njs_type_error(vm, "method is not callable");
1748	        return NJS_ERROR;
1749	    }
1750	
1751	    return NJS_OK;
1752	}
